SELECT COUNT(*) AS health_entry_count
FROM health
WHERE user_id = 0 AND date BETWEEN '2023-10-01' AND '2023-10-31';

SELECT event_name, event_date
FROM events
ORDER BY event_date DESC;

SELECT MAX(avg_heart_rate) AS highest_average_heart_rate
FROM (
    SELECT AVG(heart_rate) AS avg_heart_rate
    FROM health
    GROUP BY user_id
) AS user_avg_heart_rates;

SELECT AVG(e.distance) AS average_distance
FROM events e
JOIN event_performances ep ON e.event_id = ep.event_id;

SELECT COUNT(DISTINCT challenge_id) AS total_challenges_joined
FROM social
WHERE user_id = 1 AND status = 'joined';
